#include <iostream>
#include <vector>
#include <map>
#include <algorithm>

using namespace std;

vector<int> remove_duplicates(vector<int> numbers, int threshold) {
    map<int, int> count;
    vector<int> result;

    // Count occurrences of each number
    for (int num : numbers) {
        count[num]++;
    }

    // Iterate through the original list and add numbers that have count <= threshold
    for (int num : numbers) {
        if (count[num] <= threshold) {
            result.push_back(num);
            count[num] = threshold + 1; // Mark as processed
        }
    }

    return result;
}
```

